import{_ as e,H as o,f as i,i as a}from"./chunks/framework.Cvt1eIE0.js";const l="/quote/images/quote/history.png",r="/quote/images/quote/quote-detail.png",n="/quote/images/quote/accept_quote.png",s="/quote/images/quote/checkout.png",p="/quote/images/quote/re-quote.png",u="/quote/images/quote/print.png",c="/quote/images/quote/execl.png",h="/quote/images/quote/quote-detail-message.png",P=JSON.parse('{"title":"前台报价单管理","description":"","frontmatter":{},"headers":[],"relativePath":"quote/storefront-quote-management.md","filePath":"quote/storefront-quote-management.md"}'),g={name:"quote/storefront-quote-management.md"};function d(q,t,m,_,b,f){return o(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="前台报价单管理" tabindex="-1">前台报价单管理 <a class="header-anchor" href="#前台报价单管理" aria-label="Permalink to &quot;前台报价单管理&quot;">​</a></h1><p>本章节说明客户如何在店铺前台查看和管理自己的报价单。它适用于已经提交过报价申请、需要再次查看进度、留言沟通、接受报价或重新发起报价的场景。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>当前台报价功能已经启用后，客户通常会经历下面这条路径：</p><ol><li>在产品页、分类页或前台报价车中提交报价申请。</li><li>进入前台的 <strong>Quote History</strong> 页面查看历史报价单。</li><li>打开某一笔报价详情，继续查看状态、与商家沟通，或执行后续操作。</li></ol><h2 id="开始前先确认" tabindex="-1">开始前先确认 <a class="header-anchor" href="#开始前先确认" aria-label="Permalink to &quot;开始前先确认&quot;">​</a></h2><p>在使用前台报价单管理前，请先确认：</p><ul><li>店铺前台已经可以正常提交报价申请。</li><li>客户已经登录店铺账号。</li><li>商家已经启用前台报价入口。</li></ul><p>如果客户还没有提交过报价，前台历史页面通常会显示空状态，并引导客户先去提交第一笔报价。</p><h2 id="_1-进入前台报价历史页面" tabindex="-1">1. 进入前台报价历史页面 <a class="header-anchor" href="#_1-进入前台报价历史页面" aria-label="Permalink to &quot;1. 进入前台报价历史页面&quot;">​</a></h2><p>客户提交报价后，可以在店铺前台进入 <strong>Quote History</strong> 页面查看自己的报价记录。</p><p>常见入口有两种：</p><ul><li>从前台报价提交成功后的提示区域，点击 <strong>View History</strong>。</li><li>直接进入应用前台页面中的 <strong>Quote History</strong> 标签。</li></ul><p><img src="'+l+'" alt="前台报价历史"></p><h2 id="_2-在列表页查看自己的报价单" tabindex="-1">2. 在列表页查看自己的报价单 <a class="header-anchor" href="#_2-在列表页查看自己的报价单" aria-label="Permalink to &quot;2. 在列表页查看自己的报价单&quot;">​</a></h2><p>进入 <strong>Quote History</strong> 后，客户会先看到自己的报价单列表。这里主要用于快速查看历史记录和当前进度。</p><p>列表页通常会显示以下信息：</p><ul><li><strong>Quote ID</strong>：报价单编号。</li><li><strong>Quote name</strong>：报价名称。</li><li><strong>Customer</strong>：提交该报价的客户信息。</li><li><strong>Offer total / Total</strong>：客户期望的价格。</li><li><strong>Date</strong>：提交时间。</li><li><strong>Expires</strong>：过期时间。</li><li><strong>Status</strong>：当前状态。</li></ul><h3 id="列表页常用操作" tabindex="-1">列表页常用操作 <a class="header-anchor" href="#列表页常用操作" aria-label="Permalink to &quot;列表页常用操作&quot;">​</a></h3><p>客户在列表页通常可以进行以下操作：</p><ul><li><strong>搜索报价单</strong>：按编号或关键词查找自己的历史报价。</li><li><strong>按状态筛选</strong>：例如查看 <code>Pending</code>、<code>Sent</code>、<code>Accepted</code>、<code>Expired</code>。</li><li><strong>分页浏览</strong>：当报价记录较多时，可切换上一页或下一页。</li><li><strong>导出 Excel</strong>：如果商家开启了导出功能，客户可导出当前列表。</li><li><strong>打开详情</strong>：查看某一笔报价的完整内容与后续操作。</li></ul><h2 id="_3-查看报价详情" tabindex="-1">3. 查看报价详情 <a class="header-anchor" href="#_3-查看报价详情" aria-label="Permalink to &quot;3. 查看报价详情&quot;">​</a></h2><p>打开某一笔报价后，客户可以在详情页查看完整内容，包括：</p><ul><li>报价状态</li><li>创建时间、更新时间、有效期</li><li>报价商品明细</li><li>数量、单价、小计</li><li>运费、折扣、税费和总额</li><li>客户提交时填写的联系信息</li></ul><p><img src="'+r+'" alt="报价详情"></p><p>如果商家启用了隐藏价格功能，客户在某些状态下看到的金额信息可能会受限制。</p><h2 id="_4-在前台可以执行的操作" tabindex="-1">4. 在前台可以执行的操作 <a class="header-anchor" href="#_4-在前台可以执行的操作" aria-label="Permalink to &quot;4. 在前台可以执行的操作&quot;">​</a></h2><p>根据商家的配置不同，客户在报价详情页可能会看到以下操作按钮。</p><h3 id="接受报价" tabindex="-1">接受报价 <a class="header-anchor" href="#接受报价" aria-label="Permalink to &quot;接受报价&quot;">​</a></h3><p>如果商家开启了前台客户接受报价功能，并且该报价已经进入可确认状态，客户会看到 <strong>Accept Quote</strong> 按钮。</p><p>客户点击后，可以直接在前台确认接受该报价。</p><p><img src="'+n+'" alt="接受报价"></p><h3 id="前往结账" tabindex="-1">前往结账 <a class="header-anchor" href="#前往结账" aria-label="Permalink to &quot;前往结账&quot;">​</a></h3><p>当商家已经发送 invoice，并且该报价仍在有效期内时，客户通常会看到 <strong>checkout</strong> 按钮。</p><p>点击后会跳转到对应的 Shopify 结账或发票页面，继续完成付款。</p><p><img src="'+s+'" alt="接受报价"></p><h3 id="再次报价" tabindex="-1">再次报价 <a class="header-anchor" href="#再次报价" aria-label="Permalink to &quot;再次报价&quot;">​</a></h3><p>如果商家开启了 <strong>Re-Quote</strong> 功能，客户在以下场景下通常可以再次发起报价：</p><ul><li>该报价已经被接受</li><li>该报价已经过期</li></ul><p>点击 <strong>Re-Quote</strong> 后，原报价中的商品会重新加入前台报价车，客户可以在此基础上再次提交新的报价申请。</p><p><img src="'+p+'" alt="re-quote"></p><h3 id="打印-pdf" tabindex="-1">打印 PDF <a class="header-anchor" href="#打印-pdf" aria-label="Permalink to &quot;打印 PDF&quot;">​</a></h3><p>如果商家开启了 <strong>Print PDF</strong> 功能，客户可以在报价详情页直接打印或保存当前报价单。</p><p><img src="'+u+'" alt="print"></p><h3 id="导出-excel" tabindex="-1">导出 Excel <a class="header-anchor" href="#导出-excel" aria-label="Permalink to &quot;导出 Excel&quot;">​</a></h3><p>如果商家开启了 <strong>Export Excel</strong> 功能，客户可在前台历史列表中导出报价数据。</p><p><img src="'+c+'" alt="execl"></p><h2 id="_5-与商家留言沟通-上传附件" tabindex="-1">5. 与商家留言沟通 &amp; 上传附件 <a class="header-anchor" href="#_5-与商家留言沟通-上传附件" aria-label="Permalink to &quot;5. 与商家留言沟通 &amp; 上传附件&quot;">​</a></h2><p>如果商家开启了前台消息线程功能，客户可以在报价详情页看到留言记录，并继续回复商家。</p><p>常见可用能力包括：</p><ul><li>查看商家与客户之间的历史留言</li><li>继续发送文字消息</li><li>查看系统活动记录</li></ul><p>如果商家同时开启了“客户可回复”功能，客户会在详情页底部看到消息输入框。</p><p>如果商家开启了前台附件功能，客户在留言时还可以上传附件，例如：</p><ul><li>产品图纸</li><li>规格说明</li><li>采购清单</li><li>参考图片</li></ul><p>系统通常会限制：</p><ul><li>单次可上传的文件数量</li><li>单个文件大小</li><li>可接受的文件类型</li></ul><p>如果上传不符合限制，前台会直接提示错误。 <img src="'+h+'" alt="前台quote留言"></p><h2 id="_7-常见状态说明" tabindex="-1">7. 常见状态说明 <a class="header-anchor" href="#_7-常见状态说明" aria-label="Permalink to &quot;7. 常见状态说明&quot;">​</a></h2><p>前台常见的报价状态包括：</p><ul><li><strong>Pending</strong>：客户刚提交，等待商家处理。</li><li><strong>Reviewed</strong>：商家已经查看并更新过报价内容。</li><li><strong>Sent</strong>：商家已发送正式报价或 invoice。</li><li><strong>Accepted</strong>：客户已经接受报价。</li><li><strong>Declined</strong>：该报价未继续推进。</li><li><strong>Expired</strong>：该报价超过有效期，不能继续按原条件使用。</li></ul><h2 id="_8-推荐使用顺序" tabindex="-1">8. 推荐使用顺序 <a class="header-anchor" href="#_8-推荐使用顺序" aria-label="Permalink to &quot;8. 推荐使用顺序&quot;">​</a></h2><p>建议客户按下面顺序使用前台报价管理功能：</p><ol><li>提交报价后先进入 <strong>Quote History</strong>。</li><li>找到对应报价，打开详情查看商家是否已更新价格。</li><li>如果有疑问，先在详情页留言沟通。</li><li>如果商家已发送正式报价，确认无误后点击 <strong>Accept Quote</strong> 或直接进入结账。</li><li>如果报价已过期或需要重新谈价，再使用 <strong>Re-Quote</strong>。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="看不到-quote-history-页面" tabindex="-1">看不到 Quote History 页面 <a class="header-anchor" href="#看不到-quote-history-页面" aria-label="Permalink to &quot;看不到 Quote History 页面&quot;">​</a></h3><p>请优先检查：</p><ol><li>客户是否已经登录店铺账号。</li><li>是否已经成功提交过至少一笔报价。</li><li>商家是否已经正确启用前台报价功能。</li></ol><h3 id="列表里没有报价记录" tabindex="-1">列表里没有报价记录 <a class="header-anchor" href="#列表里没有报价记录" aria-label="Permalink to &quot;列表里没有报价记录&quot;">​</a></h3><p>请检查：</p><ol><li>当前登录的客户账号是否就是提交报价的账号。</li><li>报价是否已经成功提交，而不是中途关闭页面。</li><li>商家后台 <strong>Quotes</strong> 列表中是否已经收到该记录。</li></ol><h3 id="看不到-accept-quote-或-re-quote-按钮" tabindex="-1">看不到 Accept Quote 或 Re-Quote 按钮 <a class="header-anchor" href="#看不到-accept-quote-或-re-quote-按钮" aria-label="Permalink to &quot;看不到 Accept Quote 或 Re-Quote 按钮&quot;">​</a></h3><p>这通常表示该功能未开启，或当前报价状态还不满足显示条件。</p><p>常见原因包括：</p><ol><li>商家没有开启前台客户接受报价功能。</li><li>商家没有开启 Re-Quote 功能。</li><li>当前报价还没有进入可接受状态，或已经不适用。</li></ol>',74)])])}const k=e(g,[["render",d]]);export{P as __pageData,k as default};
